solution_code:
#include <stdio.h>

int main(void) {
    int a = 42, b = 1234, c = 7;
    printf("[%10d]\n", a);
    printf("[%-10d]\n", a);
    printf("[%10d]\n", b);
    printf("[%-10d]\n", c);
    printf("[%06d]\n", a);
    printf("[%06d]\n", b);
    return 0;
}

